module top_module(obf_ALUOP,func,alu_control_out);input [5:0] obf_ALUOP;
input [5:0] func;
output reg [5:0] alu_control_out;

always@(obf_ALUOP,func)
begin
    if(obf_ALUOP == 6'b111111)
        begin
            alu_control_out = func;
        end
    else
        begin 
            alu_control_out = obf_ALUOP;
        end

end


endmodule
